375	    /**
376	     * Builder used to create {@link SmithyIdlModelSerializer}.
377	     */
378	    public static final class Builder implements SmithyBuilder<SmithyIdlModelSerializer> {
379	        private Predicate<String> metadataFilter = FunctionalUtils.alwaysTrue();
380	        private Predicate<Shape> shapeFilter = FunctionalUtils.alwaysTrue();
381	        private Predicate<Trait> traitFilter = FunctionalUtils.alwaysTrue();
382	        private Function<Shape, Path> shapePlacer = SmithyIdlModelSerializer::placeShapesByNamespace;
383	        private Path basePath = null;
384	        private boolean serializePrelude = false;
385	        private SmithyIdlComponentOrder componentOrder = SmithyIdlComponentOrder.PREFERRED;
386	        private String inlineInputSuffix = DEFAULT_INLINE_INPUT_SUFFIX;
387	        private String inlineOutputSuffix = DEFAULT_INLINE_OUTPUT_SUFFIX;
388	        private boolean inferInlineIoSuffixes = false;
389	        private boolean shouldCoerceInlineIo = false;
390	
391	        public Builder() {}
392	
393	        /**
394	         * Predicate that determines if a metadata is serialized.
395	         *
396	         * @param metadataFilter Predicate that accepts a metadata key.
397	         * @return Returns the builder.
398	         */
399	        public Builder metadataFilter(Predicate<String> metadataFilter) {
400	            this.metadataFilter = Objects.requireNonNull(metadataFilter);
401	            return this;
402	        }
403	
404	        /**
405	         * Predicate that determines if a shape and its traits are serialized.
406	         *
407	         * @param shapeFilter Predicate that accepts a shape.
408	         * @return Returns the builder.
409	         */
410	        public Builder shapeFilter(Predicate<Shape> shapeFilter) {
411	            this.shapeFilter = Objects.requireNonNull(shapeFilter);
412	            return this;
413	        }
414	
415	        /**
416	         * Sets a predicate that can be used to filter trait values from
417	         * appearing in the serialized model.
418	         *
419	         * <p>Note that this does not filter out trait definitions. It only filters
420	         * out instances of traits from being serialized on shapes.
421	         *
422	         * @param traitFilter Predicate that filters out trait definitions.
423	         * @return Returns the builder.
424	         */
425	        public Builder traitFilter(Predicate<Trait> traitFilter) {
426	            this.traitFilter = traitFilter;
427	            return this;
428	        }
429	
430	        /**
431	         * Function that determines what output file a shape should go in.
432	         *
433	         * <p>The returned paths may be absolute or relative.
434	         *
435	         * <p>NOTE: the Smithy IDL only supports one namespace per file.
436	         *
437	         * @param shapePlacer Function that accepts a shape and returns file path.
438	         * @return Returns the builder.
439	         */
440	        public Builder shapePlacer(Function<Shape, Path> shapePlacer) {
441	            this.shapePlacer = Objects.requireNonNull(shapePlacer);
442	            return this;
443	        }
444	
445	        /**
446	         * A base path to use for any created models.
447	         *
448	         * @param basePath The base directory to assign models to.
449	         * @return Returns the builder.
450	         */
451	        public Builder basePath(Path basePath) {
452	            this.basePath = basePath;
453	            return this;
454	        }
