517	         * @param shouldInferInlineIoSuffixes Whether inline IO suffixes should be inferred for each file.
518	         * @return Returns the builder.
519	         */
520	        public Builder inferInlineIoSuffixes(boolean shouldInferInlineIoSuffixes) {
521	            this.inferInlineIoSuffixes = shouldInferInlineIoSuffixes;
522	            return this;
523	        }
524	
525	        /**
526	         * Determines whether inline IO should be coerced for shapes operation input
527	         * and output that does not have the {@code @input} or {@code @output} trait,
528	         * respectively.
529	         *
530	         * <p>If true, this will determine any shared IO suffixes for each file. Only the
531	         * shapes present within each file will impact what that file's suffixes will be.
532	         *
533	         * <p>The suffixes set by {@link #inlineInputSuffix(String)} and {@link #inlineOutputSuffix(String)}
534	         * will be the default values.
535	         *
536	         * @param shouldCoerceInlineIo Whether inline IO should be coerced for each file.
537	         * @return Returns the builder.
538	         */
539	        public Builder coerceInlineIo(boolean shouldCoerceInlineIo) {
540	            this.shouldCoerceInlineIo = shouldCoerceInlineIo;
541	            return this;
542	        }
