550	    /**
551	     * Serializes shapes in the IDL format.
552	     */
553	    private static final class ShapeSerializer extends ShapeVisitor.Default<Void> {
554	        private final SmithyCodeWriter codeWriter;
555	        private final NodeSerializer nodeSerializer;
556	        private final Predicate<Trait> traitFilter;
557	        private final Model model;
558	        private final Set<ShapeId> inlineableShapes;
559	        private final SmithyIdlComponentOrder componentOrder;
560	
561	        ShapeSerializer(
562	                SmithyCodeWriter codeWriter,
563	                NodeSerializer nodeSerializer,
564	                Predicate<Trait> traitFilter,
565	                Model model,
566	                Set<ShapeId> inlineableShapes,
567	                SmithyIdlComponentOrder componentOrder
568	        ) {
569	            this.codeWriter = codeWriter;
570	            this.nodeSerializer = nodeSerializer;
571	            this.traitFilter = traitFilter;
572	            this.model = model;
573	            this.inlineableShapes = inlineableShapes;
574	            this.componentOrder = componentOrder;
575	        }
576	
577	        @Override
578	        protected Void getDefault(Shape shape) {
579	            serializeTraits(shape);
580	            codeWriter.writeInline("$L $L ", shape.getType(), shape.getId().getName());
581	            writeMixins(shape);
582	            codeWriter.write("").write("");
583	            return null;
584	        }
585	
586	        private void shapeWithMembers(Shape shape, Collection<MemberShape> members) {
587	            shapeWithMembers(shape, members, false);
588	        }
589	
590	        private void shapeWithMembers(Shape shape, Collection<MemberShape> members, boolean isEnum) {
591	            List<MemberShape> nonMixinMembers = new ArrayList<>();
592	            List<MemberShape> mixinMembers = new ArrayList<>();
593	            for (MemberShape member : members) {
594	                if (member.getMixins().isEmpty()) {
595	                    nonMixinMembers.add(member);
596	                } else if (!member.getIntroducedTraits().isEmpty()) {
597	                    mixinMembers.add(member);
598	                }
599	            }
600	
601	            serializeTraits(shape);
602	            // IDL V2 does not support sets, so convert set to list when serializing.
603	            String v2Type = shape.getType() == ShapeType.SET ? ShapeType.LIST.toString() : shape.getType().toString();
604	            codeWriter.writeInline("$L $L ", v2Type, shape.getId().getName());
605	
606	            writeMixins(shape);
607	            if (isEnum) {
608	                writeEnumMembers(nonMixinMembers);
609	            } else {
610	                writeShapeMembers(nonMixinMembers);
611	            }
612	            codeWriter.write("");
613	            applyIntroducedTraits(mixinMembers);
614	        }
615	
616	        private void writeMixins(Shape shape) {
617	            if (shape.getMixins().size() == 1) {
618	                codeWriter.writeInline("with [$I] ", shape.getMixins().iterator().next());
619	            } else if (shape.getMixins().size() > 1) {
620	                codeWriter.write("with [").indent();
621	                for (ShapeId id : shape.getMixins()) {
622	                    // Trailing spaces are trimmed.
623	                    codeWriter.write("$I", id);
624	                }
625	                codeWriter.dedent().writeInline("] ");
626	            }
627	        }
628	
629	        private void writeShapeMembers(Collection<MemberShape> members) {
630	            if (members.isEmpty()) {
631	                // When there are no members to write, put "{}" on the same line.
632	                codeWriter.writeInline("{}").write("");
633	            } else {
634	                codeWriter.openBlock("{", "}", () -> {
635	                    for (MemberShape member : members) {
636	                        serializeTraits(member.getAllTraits(), TraitFeature.MEMBER);
637	                        String assignment = "";
638	                        if (member.hasTrait(DefaultTrait.ID)) {
639	                            assignment = " = " + Node.printJson(member.expectTrait(DefaultTrait.class).toNode());
640	                        }
641	                        codeWriter.write("$L: $I$L", member.getMemberName(), member.getTarget(), assignment);
642	                    }
643	                });
644	            }
645	        }
646	
647	        private void writeEnumMembers(Collection<MemberShape> members) {
648	            if (members.isEmpty()) {
649	                codeWriter.writeInline("{}").write("");
650	                return;
651	            }
652	
653	            codeWriter.openBlock("{", "}", () -> {
654	                for (MemberShape member : members) {
655	                    Map<ShapeId, Trait> traits = new LinkedHashMap<>(member.getAllTraits());
656	                    Optional<String> stringValue = member.expectTrait(EnumValueTrait.class).getStringValue();
657	                    boolean hasNormalName = stringValue.isPresent() && member.getMemberName().equals(stringValue.get());
658	                    String assignment = "";
659	                    if (!hasNormalName) {
660	                        assignment = " = " + Node.printJson(member.expectTrait(EnumValueTrait.class).toNode());
661	                    }
662	                    traits.remove(EnumValueTrait.ID);
663	                    serializeTraits(traits);
664	                    codeWriter.write("$L$L", member.getMemberName(), assignment);
665	                }
666	            });
667	        }
668	
669	        private void applyIntroducedTraits(Collection<MemberShape> members) {
670	            for (MemberShape member : members) {
671	                Map<ShapeId, Trait> introducedTraits = new LinkedHashMap<>(member.getIntroducedTraits());
672	
673	                // The @enumValue trait is serialized using the `=` IDL syntax, so remove it here.
674	                introducedTraits.remove(EnumValueTrait.ID);
675	
676	                // Use short form for a single trait, and block form for multiple traits.
677	                if (introducedTraits.size() == 1) {
678	                    codeWriter.writeInline("apply $I ", member.getId());
679	                    serializeTraits(member.getIntroducedTraits(), TraitFeature.NO_SPECIAL_DOCS_SYNTAX);
680	                    codeWriter.write("");
681	                } else if (!introducedTraits.isEmpty()) {
682	                    codeWriter.openBlock("apply $I {", "}", member.getId(), () -> {
683	                        // Only serialize local traits, and don't use special documentation syntax here.
684	                        serializeTraits(member.getIntroducedTraits(), TraitFeature.NO_SPECIAL_DOCS_SYNTAX);
685	                    }).write("");
686	                }
687	            }
688	        }
689	
690	        private void serializeTraits(Shape shape) {
691	            serializeTraits(shape.getIntroducedTraits());
692	        }
693	
694	        private void serializeTraits(Map<ShapeId, Trait> traits, TraitFeature... traitFeatures) {
695	            boolean noSpecialDocsSyntax = TraitFeature.NO_SPECIAL_DOCS_SYNTAX.hasFeature(traitFeatures);
696	            boolean isMember = TraitFeature.MEMBER.hasFeature(traitFeatures);
697	
698	            // The documentation trait always needs to be serialized first since it uses special syntax.
699	            if (!noSpecialDocsSyntax && traits.containsKey(DocumentationTrait.ID)) {
700	                Trait documentation = traits.get(DocumentationTrait.ID);
701	                if (traitFilter.test(documentation)) {
702	                    serializeDocumentation(documentation.toNode().expectStringNode().getValue());
703	                }
704	            }
705	
706	            Comparator<Trait> traitComparator = componentOrder.toShapeIdComparator();
707	
708	            traits.values()
709	                    .stream()
710	                    .filter(trait -> noSpecialDocsSyntax || !trait.toShapeId().equals(DocumentationTrait.ID))
711	                    // The default and enumValue traits are serialized using the assignment syntactic sugar.
712	                    .filter(trait -> {
713	                        if (trait instanceof EnumValueTrait) {
714	                            return false;
715	                        } else {
716	                            // Default traits are serialized normally for non-members, but omitted for members.
717	                            return !isMember || !(trait instanceof DefaultTrait);
718	                        }
719	                    })
720	                    .filter(traitFilter)
721	                    .sorted(traitComparator)
722	                    .forEach(this::serializeTrait);
723	        }
724	
725	        private void serializeDocumentation(String documentation) {
726	            // The documentation trait has a special syntax, which we always want to use.
727	            codeWriter
728	                    .pushState()
729	                    // See https://github.com/smithy-lang/smithy/issues/2115
730	                    .trimTrailingSpaces(false)
731	                    .setNewlinePrefix("/// ")
732	                    .write(documentation.replace("$", "$$"))
733	                    .popState();
734	        }
735	
736	        private void serializeTrait(Trait trait) {
737	            Node node = trait.toNode();
738	            // We won't fail if the trait can't be found.
739	            Shape shape = model.getShape(trait.toShapeId()).orElse(null);
740	
741	            if (shape != null && (trait instanceof AnnotationTrait || isEmptyStructure(node, shape))) {
742	                // Traits that inherit from AnnotationTrait specifically can omit a value.
743	                // Traits that are simply boolean shapes which don't implement AnnotationTrait cannot.
744	                // Additionally, empty structure traits can omit a value.
745	                codeWriter.write("@$I", trait.toShapeId());
746	            } else if (node.isObjectNode()) {
747	                codeWriter.writeIndent().openBlockInline("@$I(", trait.toShapeId());
748	                nodeSerializer.serializeKeyValuePairs(node.expectObjectNode(), shape);
749	                codeWriter.closeBlock(")");
750	            } else {
751	                codeWriter.writeIndent().writeInline("@$I(", trait.toShapeId());
752	                nodeSerializer.serialize(node, shape);
753	                codeWriter.write(")");
754	            }
755	        }
756	
757	        private boolean isEmptyStructure(Node node, Shape shape) {
758	            return !shape.isDocumentShape() && node.asObjectNode().map(ObjectNode::isEmpty).orElse(false);
759	        }
