797	        @Override
798	        public Void serviceShape(ServiceShape shape) {
799	            serializeTraits(shape);
800	            codeWriter.writeInline("service $L ", shape.getId().getName());
801	            writeMixins(shape);
802	            codeWriter.openBlock("{");
803	
804	            if (!StringUtils.isBlank(shape.getIntroducedVersion())) {
805	                codeWriter.write("version: $S", shape.getIntroducedVersion());
806	            }
807	
808	            codeWriter.writeOptionalIdList("operations", shape.getIntroducedOperations());
809	            codeWriter.writeOptionalIdList("resources", shape.getIntroducedResources());
810	            codeWriter.writeOptionalIdList("errors", shape.getIntroducedErrorsSet());
811	            if (!shape.getIntroducedRename().isEmpty()) {
812	                codeWriter.openBlock("rename: {", "}", () -> {
813	                    for (Map.Entry<ShapeId, String> entry : shape.getIntroducedRename().entrySet()) {
814	                        codeWriter.write("$S: $S", entry.getKey(), entry.getValue());
