822	        @Override
823	        public Void resourceShape(ResourceShape shape) {
824	            serializeTraits(shape);
825	            codeWriter.writeInline("resource $L ", shape.getId().getName());
826	            writeMixins(shape);
827	            codeWriter.openBlock("{");
828	            if (!shape.getIdentifiers().isEmpty()) {
829	                codeWriter.openBlock("identifiers: {");
830	                shape.getIdentifiers()
831	                        .entrySet()
832	                        .stream()
833	                        .sorted(Map.Entry.comparingByKey())
834	                        .forEach(entry -> codeWriter.write(
835	                                "$L: $I",
836	                                entry.getKey(),
837	                                entry.getValue()));
838	                codeWriter.closeBlock("}");
839	            }
840	            if (shape.hasProperties()) {
841	                codeWriter.openBlock("properties: {");
842	                shape.getProperties().forEach((name, shapeId) -> codeWriter.write("$L: $I", name, shapeId));
843	                codeWriter.closeBlock("}");
844	            }
845	
846	            shape.getPut().ifPresent(shapeId -> codeWriter.write("put: $I", shapeId));
847	            shape.getCreate().ifPresent(shapeId -> codeWriter.write("create: $I", shapeId));
848	            shape.getRead().ifPresent(shapeId -> codeWriter.write("read: $I", shapeId));
849	            shape.getUpdate().ifPresent(shapeId -> codeWriter.write("update: $I", shapeId));
850	            shape.getDelete().ifPresent(shapeId -> codeWriter.write("delete: $I", shapeId));
851	            shape.getList().ifPresent(shapeId -> codeWriter.write("list: $I", shapeId));
852	            codeWriter.writeOptionalIdList("operations", shape.getIntroducedOperations());
853	            codeWriter.writeOptionalIdList("collectionOperations", shape.getCollectionOperations());
854	            codeWriter.writeOptionalIdList("resources", shape.getIntroducedResources());
855	            codeWriter.closeBlock("}");
856	            codeWriter.write("");
857	            return null;
858	        }
