860	        @Override
861	        public Void operationShape(OperationShape shape) {
862	            serializeTraits(shape);
863	            codeWriter.writeInline("operation $L ", shape.getId().getName());
864	            writeMixins(shape);
865	            codeWriter.openBlock("{");
866	            List<MemberShape> mixinMembers = new ArrayList<>();
867	            mixinMembers.addAll(writeInlineableProperty("input", shape.getInputShape(), InputTrait.ID));
868	            mixinMembers.addAll(writeInlineableProperty("output", shape.getOutputShape(), OutputTrait.ID));
869	            codeWriter.writeOptionalIdList("errors", shape.getIntroducedErrorsSet());
870	            codeWriter.closeBlock("}");
871	            codeWriter.write("");
872	            applyIntroducedTraits(mixinMembers);
873	            return null;
874	        }
