876	        private Collection<MemberShape> writeInlineableProperty(String key, ShapeId shapeId, ShapeId defaultTrait) {
877	            if (!inlineableShapes.contains(shapeId)) {
878	                codeWriter.write("$L: $I", key, shapeId);
879	                return Collections.emptyList();
880	            }
881	
882	            StructureShape structure = model.expectShape(shapeId, StructureShape.class);
883	            if (hasOnlyDefaultTrait(structure, defaultTrait)) {
884	                codeWriter.writeInline("$L := ", key);
885	            } else {
886	                codeWriter.write("$L := ", key);
887	                codeWriter.indent();
888	                Map<ShapeId, Trait> traits = structure.getAllTraits();
889	                if (defaultTrait != null) {
890	                    traits = new HashMap<>(traits);
891	                    traits.remove(defaultTrait);
892	                }
893	                serializeTraits(traits);
894	            }
895	
896	            List<MemberShape> nonMixinMembers = new ArrayList<>();
897	            List<MemberShape> mixinMembers = new ArrayList<>();
898	            for (MemberShape member : structure.members()) {
899	                if (member.getMixins().isEmpty()) {
900	                    nonMixinMembers.add(member);
901	                } else if (!member.getIntroducedTraits().isEmpty()) {
902	                    mixinMembers.add(member);
903	                }
904	            }
905	
906	            writeMixins(structure);
907	            writeShapeMembers(nonMixinMembers);
908	
909	            if (!hasOnlyDefaultTrait(structure, defaultTrait)) {
910	                codeWriter.dedent();
911	            }
912	
913	            return mixinMembers;
914	        }
915	
916	        private boolean hasOnlyDefaultTrait(Shape shape, ShapeId defaultTrait) {
917	            return shape.getAllTraits().isEmpty() || (shape.getAllTraits().size() == 1 && shape.hasTrait(defaultTrait));
918	        }
919	    }
