@Test
    public void serializesIdRefInTraitValueAsQuotedString() {
        // When a trait member has @idRef, the value is a shape ID. When serializing,
        // it should be quoted so that the serialized model can round-trip correctly
        // even when the referenced shape doesn't exist in the model.
        String modelStr = "$version: \"2\"\n"
                + "namespace test\n"
                + "\n"
                + "@trait\n"
                + "structure myTrait {\n"
                + "    @idRef\n"
                + "    @required\n"
                + "    s: String\n"
                + "}\n"
                + "\n"
                + "@myTrait(s: \"foo.bar#Baz\")\n"
                + "string Demo\n";

        Model model = Model.assembler()
                .addUnparsedModel("test.smithy", modelStr)
                .assemble()
                .unwrap();

        SmithyIdlModelSerializer serializer = SmithyIdlModelSerializer.builder().build();
        Map<Path, String> serialized = serializer.serialize(model);

        // Find the serialized content that contains the model
        String output = serialized.values().stream()
                .filter(v -> v.contains("namespace test"))
                .findFirst()
                .orElseThrow();

        // The @idRef value should be serialized as a quoted string, not an unquoted shape ID
        assertThat(output, containsString("\"foo.bar#Baz\""));

        // It should NOT be serialized as an unquoted reference (which would cause a use import)
        assertThat(output, not(containsString("use foo.bar#Baz")));
    }

