private void serializeShapeId(StringNode node) {
            // Convert the string value to a ShapeId. If the value refers to a shape
            // that does not exist in the model, serialize it as a quoted string instead
            // of an unquoted shape ID reference. This ensures round-trip correctness
            // when @idRef is used without failWhenMissing and the referenced shape does
