            // to something within the current namespace context and should be serialized
            // as unquoted shape IDs. Only check for existence for absolute ShapeIds.
            if (shapeId.getNamespace() != null && !model.getShape(shapeId).isPresent()) {
                serializeString(node);
                return;
            }
            codeWriter.writeInline("$I", node.getValue());
        }

