private void serializeShapeId(StringNode node) {
    // Convert the string value to a ShapeId. If the value refers to a shape
    // that does not exist in the model, serialize it as a quoted string instead
    // of an unquoted shape ID reference. This ensures round-trip correctness
    // when @idRef is used without failWhenMissing and the referenced shape does
    // not exist.
    String value = node.getValue();
    ShapeId shapeId = ShapeId.from(value);
    // ShapeIds without a namespace are relative references, which always resolve
    // to something within the current namespace context and should be serialized
    // as unquoted shape IDs. Only check for existence for absolute ShapeIds.
    if (shapeId.getNamespace() != null && !model.getShape(shapeId).isPresent()) {
        serializeString(node);
        return;
    }

